"use client";

import { useEffect, useMemo, useState } from "react";

import { DiaryPanel } from "@/components/diary";
import type { GameState } from "@engine/state";
import { composeDiary } from "@harness/diary";

import styles from "./TitleScreen.module.css";
import {
  createTitleSeed,
  createTitleViewModel,
  nextRunMemoryNote,
  terminalRunViewModel,
} from "./model";

type TitleScreenProps = {
  readonly activeRun: GameState | null;
  readonly terminalRun: GameState | null;
  readonly onContinue: () => void;
  readonly onNewRun: (seed: string) => void;
  readonly onRunIndex: () => void;
  readonly onSettings: () => void;
};

export function TitleScreen({
  activeRun,
  terminalRun,
  onContinue,
  onNewRun,
  onRunIndex,
  onSettings,
}: TitleScreenProps) {
  const [seed, setSeed] = useState(() => createTitleSeed());
  const terminal = terminalRun === null ? null : terminalRunViewModel(terminalRun);
  const terminalDiary = useMemo(
    () => (terminalRun === null ? null : composeDiary({ state: terminalRun })),
    [terminalRun],
  );
  const model = useMemo(
    () => createTitleViewModel({ activeRun, seed }),
    [activeRun, seed],
  );

  useEffect(() => {
    const onKeyDown = (event: KeyboardEvent): void => {
      if (isEditableTarget(event.target)) {
        return;
      }

      if (event.key === ">") {
        event.preventDefault();
        onNewRun(seed);
      }
    };

    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [onNewRun, seed]);

  if (terminal !== null && terminalDiary !== null) {
    return (
      <section className={styles.screen} aria-label="Run diary">
        <div className={styles.surface}>The Last Lantern</div>
        <DiaryPanel diary={terminalDiary} variant="final" />
        <p className={styles.terminalNote}>{nextRunMemoryNote(terminal)}</p>
        <div className={styles.actions}>
          <button type="button" onClick={() => onNewRun(seed)}>
            New run
          </button>
          <button type="button" onClick={onRunIndex}>
            Run index
          </button>
        </div>
      </section>
    );
  }

  return (
    <section className={styles.screen} aria-label="Title">
      <div className={styles.surface}>The Last Lantern</div>
      <div className={styles.titleBlock}>
        <h1>Everdeep</h1>
        <p>Seed {model.seed}</p>
      </div>
      <div className={styles.actions}>
        {model.actions.includes("continue") ? (
          <button type="button" onClick={onContinue}>
            Continue
          </button>
        ) : null}
        <button type="button" onClick={() => onNewRun(seed)}>
          New run
        </button>
        <button type="button" onClick={onRunIndex}>
          Run index
        </button>
        <button type="button" onClick={onSettings}>
          Settings
        </button>
      </div>
      <button
        className={styles.seedButton}
        type="button"
        onClick={() => setSeed(createTitleSeed(Date.now() + 1))}
      >
        Reroll seed
      </button>
    </section>
  );
}

const isEditableTarget = (target: EventTarget | null): boolean => {
  if (!(target instanceof HTMLElement)) {
    return false;
  }

  const tagName = target.tagName.toLowerCase();
  return target.isContentEditable || tagName === "input" || tagName === "textarea";
};

"use client";

import { useEffect, useMemo, useState, type CSSProperties } from "react";

import { useGameStore } from "@/store/game-store";

import styles from "./FloorTransitionOverlay.module.css";
import {
  transitionPresentation,
  type FloorTransitionState,
} from "./model";

type FloorTransitionOverlayProps = {
  readonly transition: FloorTransitionState | null;
  readonly onSkip: () => void;
};

export function FloorTransitionOverlay({
  transition,
  onSkip,
}: FloorTransitionOverlayProps) {
  const [nowMs, setNowMs] = useState(() => performanceNow());
  const introLine = useGameStore((state) => state.arrivalIntroLine);

  useEffect(() => {
    if (transition === null) {
      return;
    }

    const id = window.setInterval(() => setNowMs(performanceNow()), 80);
    return () => window.clearInterval(id);
  }, [transition]);

  useEffect(() => {
    if (transition === null) {
      return;
    }

    const onKeyDown = (event: KeyboardEvent): void => {
      if (!transition.floorReady || transition.phase !== "descending") {
        return;
      }

      event.preventDefault();
      event.stopPropagation();
      onSkip();
    };

    window.addEventListener("keydown", onKeyDown, { capture: true });
    return () => window.removeEventListener("keydown", onKeyDown, { capture: true });
  }, [onSkip, transition]);

  const presentation = useMemo(
    () => (transition === null ? null : transitionPresentation(transition, nowMs)),
    [nowMs, transition],
  );

  if (transition === null || presentation === null) {
    return null;
  }

  return (
    <div
      className={[
        styles.overlay,
        presentation.phase === "arrival" ? styles.arrival : styles.descending,
      ]
        .filter(Boolean)
        .join(" ")}
      data-transition-phase={presentation.phase}
      data-shimmer={presentation.shimmerVisible ? "true" : "false"}
      data-skip-enabled={presentation.skipEnabled ? "true" : "false"}
      aria-live="polite"
    >
      <div className={styles.panel}>
        <div className={styles.floor}>{presentation.floorLabel}</div>
        <div className={styles.whisper}>{presentation.whisper}</div>
        {presentation.shimmerVisible ? (
          <div
            className={styles.shimmerTrack}
            aria-hidden="true"
            style={{ "--gg-transition-shimmer": `${presentation.shimmerPercent}%` } as CSSProperties}
          >
            <span className={styles.shimmerFill} />
          </div>
        ) : null}
        {presentation.phase === "arrival" ? (
          <div
            className={styles.arrivalLine}
            data-arrival-progress={presentation.arrivalProgress.toFixed(2)}
            data-entrance-pulse={presentation.entrancePulse ? "true" : "false"}
          >
            {introLine ?? presentation.whisper}
          </div>
        ) : null}
      </div>
    </div>
  );
}

const performanceNow = (): number =>
  typeof performance === "undefined" ? Date.now() : performance.now();

